text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 스모크 테스트가 통과될 경우 금요일 15:00 KST로 한다.",
        "conditions": ["스모크 테스트 통과"]
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "conditions": ["계약 자체가 잘못된 경우에만 스크립트 검토"]
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "result": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "내부 stretch goal일 뿐이며 최종 릴리스 결정 아님"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 목요일까지 가능하면 검토해야 한다는 의견이 있었으나 담당자가 배정되지 않았다."
      },
      {
        "item": "릴리스 노트에 내부 수요일 stretch goal을 언급할지는 결정되지 않았다."
      }
    ],
    "risks": [
      "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
      "README 설치 단계가 오래된 경우 릴리스 노트가 사용자를 오도할 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "확정, 정확한 마감 없음",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능하면",
      "status": "담당자 미배정",
      "source_certainty": "mentioned_not_assigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과",
      "스모크 통과 여부에 따른 금요일 15:00 KST 공개 릴리스 가능성",
      "Doyun의 action_items.md 실패 triage note 작성 여부",
      "Hara의 tarball 경로 확인 결과",
      "README 설치 단계 검토 담당자 배정 여부",
      "최종 릴리스 승인 권한자 확인",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정"
    ],
    "do_not_invent": [
      "고객 또는 외부 파트너 이름",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "고객명은 언급되지 않았으므로 생성하지 않는다.",
    "예산, 보안 사고, 프로덕션 장애, 법무 승인 요구사항은 언급되지 않았으므로 사실로 쓰지 않는다.",
    "담당자가 없는 README 검토 항목에 임의 담당자를 배정하지 않는다.",
    "Hara의 tarball 경로 확인에는 정확한 마감이 없으므로 임의 마감일을 만들지 않는다.",
    "수요일 릴리스는 최종 결정이 아니라 내부 stretch goal로만 기록한다.",
    "packageName 불일치 무시 제안은 거절된 제안으로만 기록한다."
  ]
}
